#!/usr/bin/env python3
"""GBAVC - GBA Video Converter. pip install customtkinter Pillow numpy"""
import sys, subprocess

# ── Auto-install missing packages on first run ────────────────────────────
def _install(pkg):
    """Try pip install, fall back to --break-system-packages for uv/managed envs."""
    for extra in ([], ["--break-system-packages"]):
        try:
            subprocess.check_call(
                [sys.executable, "-m", "pip", "install"] + extra + [pkg],
                stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
            return True
        except subprocess.CalledProcessError:
            continue
    return False

def _boot():
    missing = []
    try: import customtkinter
    except ImportError: missing.append("customtkinter")
    try: import numpy
    except ImportError: missing.append("numpy")
    try: import PIL
    except ImportError: missing.append("Pillow")
    try: import imageio_ffmpeg
    except ImportError: missing.append("imageio-ffmpeg")  # bundles ffmpeg — no PATH needed!
    if not missing:
        return   # all good — continue straight to app

    import tkinter as _tk
    from tkinter import messagebox as _mb
    r = _tk.Tk(); r.withdraw()
    if not _mb.askyesno("GBAVC",
            "Missing packages: " + ", ".join(missing) +
            "\n\nInstall now?  (requires internet)"):
        _mb.showerror("GBAVC", "Cannot start without required packages.")
        sys.exit(1)

    failed = []
    for p in missing:
        if not _install(p):
            failed.append(p)

    if failed:
        _mb.showerror("GBAVC",
            "Failed to install: " + ", ".join(failed) +
            "\n\nTry manually:\n  pip install " + " ".join(failed))
        sys.exit(1)

    # Auto-restart — no manual step needed
    subprocess.Popen([sys.executable] + sys.argv)
    sys.exit(0)

_boot()
