def find_ffmpeg():
    # Priority 1: imageio-ffmpeg pip package — bundles its own binary, no PATH needed
    try:
        import imageio_ffmpeg
        p = imageio_ffmpeg.get_ffmpeg_exe()
        if p and os.path.isfile(p):
            return p
    except Exception:
        pass

    import shutil, glob
    # 1. Standard PATH lookup
    p = shutil.which("ffmpeg") or shutil.which("ffmpeg.exe")
    if p: return p

    # 2. Windows: use "where" command (reads PATH differently than Python)
    try:
        r = subprocess.run(["where","ffmpeg"], capture_output=True, text=True, timeout=5)
        if r.returncode == 0:
            line = r.stdout.strip().splitlines()[0].strip()
            if os.path.isfile(line): return line
    except Exception: pass

    # 3. Common install locations
    lad   = os.environ.get("LOCALAPPDATA",  "")
    pad   = os.environ.get("ProgramFiles",   os.path.join("C:\\","Program Files"))
    pad86 = os.environ.get("ProgramFiles(x86)", r"C:\Program Files (x86)")
    home  = os.environ.get("USERPROFILE",   os.path.expanduser("~"))
    script_dir = os.path.dirname(os.path.abspath(__file__))

    fixed_paths = [
        os.path.join(script_dir, "ffmpeg.exe"),          # next to script — easiest
        r"C:fmpeginfmpeg.exe",
        os.path.join(pad,  "ffmpeg", "bin", "ffmpeg.exe"),
        os.path.join(pad86,"ffmpeg", "bin", "ffmpeg.exe"),
        os.path.join(home, "ffmpeg", "bin", "ffmpeg.exe"),
        os.path.join(home, "scoop",  "apps", "ffmpeg", "current", "bin", "ffmpeg.exe"),  # scoop
        os.path.join(home, ".local", "bin", "ffmpeg.exe"),
    ]
    for c in fixed_paths:
        if os.path.isfile(c): return c

    # 4. Winget packages folder (glob because version folder name changes)
    winget_root = os.path.join(lad, "Microsoft", "WinGet", "Packages")
    patterns = [
        os.path.join(winget_root, "*ffmpeg*", "**", "ffmpeg.exe"),
        os.path.join(winget_root, "Gyan.FFmpeg*", "**", "ffmpeg.exe"),
    ]
    for pat in patterns:
        matches = glob.glob(pat, recursive=True)
        if matches: return matches[0]

    # 5. Chocolatey
    choco = os.path.join(os.environ.get("ChocolateyInstall", r"C:\ProgramData\chocolatey"), "bin", "ffmpeg.exe")
    if os.path.isfile(choco): return choco

    return None

# ── Config: remember user-selected ffmpeg path across sessions ────────────
_CONFIG = os.path.join(os.path.dirname(os.path.abspath(__file__)), "gbavc_config.json")

def load_config():
    try:
        with open(_CONFIG) as _f: return json.load(_f)
    except Exception: return {}

def save_config(data):
    try:
        with open(_CONFIG, "w") as _f: json.dump(data, _f, indent=2)
    except Exception: pass

_saved = load_config().get("ffmpeg_path", "")
FFMPEG_EXE = (_saved if _saved and os.path.isfile(_saved) else find_ffmpeg())

def check_ffmpeg():
    return FFMPEG_EXE is not None

def get_video_info(path):
    import shutil
    ffprobe=shutil.which("ffprobe") or (os.path.join(os.path.dirname(FFMPEG_EXE),"ffprobe.exe") if FFMPEG_EXE else None)
    exe=ffprobe if ffprobe and os.path.isfile(ffprobe) else FFMPEG_EXE
    if not exe: return {}
    cmd=[exe,"-v","quiet","-print_format","json","-show_streams","-show_format",path]
    try:
        r=subprocess.run(cmd,capture_output=True,text=True,timeout=15)
        d=json.loads(r.stdout)
    except: return {}
    info={}
    for s in d.get("streams",[]):
        if s.get("codec_type")=="video":
            info["width"]=s.get("width",0); info["height"]=s.get("height",0)
            try:
                n,dd=s.get("r_frame_rate","25/1").split("/")
                info["fps"]=round(int(n)/int(dd),2)
            except: info["fps"]=25.0
    dur=d.get("format",{}).get("duration")
    if dur: info["duration"]=float(dur)
    return info

def extract_frames(path,fps,w,h,stop_evt=None):
    cmd=[(FFMPEG_EXE or "ffmpeg"),"-i",path,"-vf",f"fps={fps},scale={w}:{h}:flags=lanczos",
         "-f","rawvideo","-pix_fmt","rgb24","-"]
    proc=subprocess.Popen(cmd,stdout=subprocess.PIPE,stderr=subprocess.DEVNULL)
    fsz=w*h*3; idx=0
    try:
        while True:
            if stop_evt and stop_evt.is_set(): break
            raw=proc.stdout.read(fsz)
            if len(raw)<fsz: break
            yield idx,np.frombuffer(raw,dtype=np.uint8).reshape(h,w,3).copy()
            idx+=1
    finally:
        proc.stdout.close(); proc.wait()

def extract_audio(path,rate=AUDIO_RATE):
    try:
        cmd=[(FFMPEG_EXE or "ffmpeg"),"-i",path,"-vn","-ac","1","-ar",str(rate),
             "-f","s8","-acodec","pcm_s8","-"]
        p=subprocess.run(cmd,capture_output=True,timeout=120)
        d=np.frombuffer(p.stdout,dtype=np.int8)
        if len(d)==0: return None
        mx=np.abs(d).max()
        if mx>0: d=np.clip(d.astype(np.float32)*127/mx,-128,127).astype(np.int8)
        return d
    except: return None

def median_cut(rgb,n=256):
    pts=rgb.reshape(-1,3).astype(np.float32)[::max(1,len(rgb.reshape(-1,3))//8192)]
    bks=[pts]
    while len(bks)<n:
        bi,br=0,-1
        for i,bk in enumerate(bks):
            if len(bk)<2: continue
            r=(bk.max(0)-bk.min(0)).max()
            if r>br: br=r; bi=i
        bk=bks[bi]
        if len(bk)<2 or br==0: break
        ch=int((bk.max(0)-bk.min(0)).argmax())
        bk=bk[bk[:,ch].argsort()]; mid=len(bk)//2
        del bks[bi]; bks.insert(bi,bk[:mid]); bks.insert(bi+1,bk[mid:])
    while len(bks)<n: bks.append(np.zeros((1,3),dtype=np.float32))
    return np.array([bk.mean(0) for bk in bks],dtype=np.uint8)

def build_lut(pal):
    r5,g5,b5=np.mgrid[0:32,0:32,0:32]
    pts=np.stack([(r5.flatten()*8+4),(g5.flatten()*8+4),(b5.flatten()*8+4)],axis=1).astype(np.int32)
    diff=pts[:,None,:]-pal.astype(np.int32)[None,:,:]
    return (diff**2).sum(2).argmin(1).astype(np.uint8)

def quantize(rgb,lut):
    r5=(rgb[:,:,0]>>3).astype(np.int32); g5=(rgb[:,:,1]>>3).astype(np.int32); b5=(rgb[:,:,2]>>3).astype(np.int32)
    return lut[(r5<<10)|(g5<<5)|b5].flatten()

def pal_bgr15(pal):
    buf=bytearray(512)
    for i,(r,g,b) in enumerate(pal): struct.pack_into("<H",buf,i*2,(int(b)>>3)<<10|(int(g)>>3)<<5|(int(r)>>3))
    return bytes(buf)

def rle_encode(px):
    out=bytearray(); i=0; n=len(px)
    while i<n:
        v=int(px[i]); run=1
        while run<129 and i+run<n and int(px[i+run])==v: run+=1
        if run>=3: out.append(run-2); out.append(v); i+=run
        else:
            ls=i; ll=0
            while ll<128 and i<n:
                a=1
                while a<3 and i+a<n and int(px[i+a])==int(px[i]): a+=1
                if a>=3 and ll>0: break
                ll+=1; i+=1
            out.append(0x80|(ll-1)); out.extend(int(x) for x in px[ls:ls+ll])
    return bytes(out)

def encode_delta(prev,curr,gap=8):
    diff=(curr!=prev); out=bytearray(); n=len(curr); i=0
    while i<n:
        if not diff[i]: i+=1; continue
        s=i; j=i+1; g=0
        while j<n and j-s<65534:
            if diff[j]: g=0; j+=1
            elif g<gap: g+=1; j+=1
            else: break
        while j>i and not diff[j-1]: j-=1
        out+=struct.pack("<HH",s,j-i); out.extend(int(x) for x in curr[s:j]); i=j
    out+=b"\xff\xff"; return bytes(out)

def assemble_rom(frames,w,h,fps,kf,audio):
    player=base64.b64decode(PLAYER_B64)
    vbytes=sum(5+len(f["data"]) for f in frames)
    has_a=audio is not None and len(audio)>0
    hdr=struct.pack("<4sHHBBBBIIIHH",b"GVCP",w,h,fps,kf,1 if has_a else 0,0,
                   len(frames),28+vbytes if has_a else 0,len(audio) if has_a else 0,
                   AUDIO_TM0_RELOAD if has_a else 0,0)
    assert len(hdr)==28
    rom=bytearray(player)+hdr
    for f in frames: rom+=bytes([f["type"]])+struct.pack("<I",len(f["data"]))+f["data"]
    if has_a: rom+=audio.tobytes()
    rom[0xBD]=(-(sum(rom[0xA0:0xBD])+0x19))&0xFF
    return bytes(rom)

def human_size(n):
    if n<1024: return f"{n} B"
    if n<1048576: return f"{n/1024:.1f} KB"
    return f"{n/1048576:.2f} MB"

