class DropZone(tk.Canvas):
    """Dashed-border drop zone — matches the web version look."""
    def __init__(self, master, on_click=None, **kw):
        super().__init__(master, bg=C["surface"], highlightthickness=0,
                         cursor="hand2", **kw)
        self._on_click = on_click
        self._ready    = False
        self._hover    = False
        self.bind("<Configure>",  self._draw)
        self.bind("<Enter>",      lambda e: self._set_hover(True))
        self.bind("<Leave>",      lambda e: self._set_hover(False))
        self.bind("<Button-1>",   lambda e: on_click and on_click())

    def set_ready(self, filename):
        self._ready = True
        self._fname = filename
        self._draw()

    def reset(self):
        self._ready = False
        self._draw()

    def _set_hover(self, v):
        self._hover = v; self._draw()

    def _draw(self, event=None):
        self.delete("all")
        W = self.winfo_width();  H = self.winfo_height()
        if W < 8 or H < 8: return
        pad = 6
        border = (C["green"] if self._ready
                  else C["accent"] if self._hover
                  else C["border"])
        fill   = "#1a1a30" if self._hover else C["surface"]
        self.configure(bg=fill)
        self.create_rectangle(pad, pad, W-pad, H-pad,
            outline=border, dash=(12, 6), width=2, fill=fill)

        cx, cy = W//2, H//2
        if self._ready:
            self.create_text(cx, cy-14, text="✓", font=("Segoe UI",28),
                             fill=C["green"], anchor="center")
            name = getattr(self,"_fname","")
            if len(name)>38: name = "…"+name[-36:]
            self.create_text(cx, cy+18, text=name,
                             font=("Courier New",10), fill=C["text"], anchor="center")
            self.create_text(cx, cy+36, text="click to change file",
                             font=("Courier New",9), fill=C["muted"], anchor="center")
        else:
            self.create_text(cx, cy-20, text="🎬",
                             font=("Segoe UI",32), fill=C["muted"], anchor="center")
            self.create_text(cx, cy+12, text="Drop video here  or  click to browse",
                             font=("Courier New",11), fill=C["text"], anchor="center")
            self.create_text(cx, cy+30, text="MP4  ·  AVI  ·  MKV  ·  MOV  ·  WMV  ·  FLV  ·  WebM  ·  MPEG",
                             font=("Courier New",9), fill=C["muted"], anchor="center")


class SectionLabel(ctk.CTkLabel):
    """Small all-caps section header with accent colour."""
    def __init__(self, master, text, **kw):
        super().__init__(master, text=text,
                         font=ctk.CTkFont(family="Courier New", size=10, weight="bold"),
                         text_color=C["accent2"], **kw)


class StatRow(ctk.CTkFrame):
    """Label + right-aligned value pair."""
    def __init__(self, master, label, **kw):
        super().__init__(master, fg_color="transparent", **kw)
        self.grid_columnconfigure(1, weight=1)
        ctk.CTkLabel(self, text=label,
                     font=ctk.CTkFont(family="Courier New", size=11),
                     text_color=C["muted"]).grid(row=0, column=0, sticky="w")
        self._val = ctk.CTkLabel(self, text="—",
                                 font=ctk.CTkFont(family="Courier New",size=11,weight="bold"),
                                 text_color=C["accent2"])
        self._val.grid(row=0, column=1, sticky="e")

    def set(self, v): self._val.configure(text=v)


class LogBox(ctk.CTkTextbox):
    """Styled monospace log with colour tags."""
    def __init__(self, master, **kw):
        super().__init__(master,
                         font=ctk.CTkFont(family="Courier New", size=11),
                         fg_color=C["surface"], text_color=C["muted"],
                         corner_radius=6, state="disabled", **kw)
        self.tag_config("ok",   foreground=C["green"])
        self.tag_config("warn", foreground=C["yellow"])
        self.tag_config("err",  foreground=C["red"])

    def append(self, msg, tag=""):
        self.configure(state="normal")
        self.insert("end", f"> {msg}\n", tag or ())
        self.see("end")
        self.configure(state="disabled")

    def clear(self):
        self.configure(state="normal"); self.delete("1.0","end")
        self.configure(state="disabled")


